INSERT INTO public.navigations (sort_order, label, route_or_surface, navigation_group, layout_position, meaning, purpose, visible_to, notes, source_reference) VALUES
  (1, 'Dashboard', '/dashboard', 'Workspace', 'Left sidebar → Workspace', 'Workspace overview for the active page', 'Land on the workspace home', 'all users', 'Core module, always accessible. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (2, 'Analytics', '/analytics', 'Workspace', 'Left sidebar → Workspace', 'Page metrics over time', 'View performance charts', 'module_access:analytics', 'Page-scoped. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (3, 'Insights', '/insights', 'Workspace', 'Left sidebar → Workspace', 'Insight reports', 'Open insight reports; expands sub-nav when active', 'module_access:insights', 'Sub-nav: Overview / Performance / Messaging / Contents (?view=). Pinnable.', 'client/src/components/AppLayout.jsx'),
  (4, 'Contents', '/post-pool', 'Workspace', 'Left sidebar → Workspace', 'Post pool (posts, reels, stories, comments)', 'Review and manage content', 'module_access:post-pool', 'Label "Contents", route /post-pool. Sub-nav: Posts & reels / Stories / Comments (?view=). Pinnable.', 'client/src/components/AppLayout.jsx'),
  (5, 'Upload', '/upload', 'Workspace', 'Left sidebar → Workspace', 'Content creation and scheduling', 'Create, prepare, and schedule posts', 'module_access:upload', 'Page-scoped. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (6, 'Shop', '/shop', 'Workspace', 'Left sidebar → Workspace', 'Shop module (catalog, orders)', 'Open the shop tools', 'module_access:products', 'Module id is "products". Sub-nav rail on the page: Products / Orders / Receipts / Discounts. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (7, 'Messaging', '/messages', 'General', 'Left sidebar → General', 'Customer inbox + teammate DMs', 'Open conversations and reply', 'module_access:messages', 'Carries an unread badge. Page-scoped. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (8, 'Connections', '/connections', 'General', 'Left sidebar → General', 'Teammate connections for A2A messaging', 'Manage connections and requests', 'module_access:connections', 'Carries a pending-request badge. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (9, 'Content Calendar', '/content-calendar', 'General', 'Left sidebar → General', 'Calendar of scheduled content', 'View planned/scheduled posts across pages', 'module_access:content-calendar', 'Page-independent (spans all pages). Pinnable.', 'client/src/components/AppLayout.jsx'),
  (10, 'Planner', '/planner', 'General', 'Left sidebar → General', 'Per-page goals and progress', 'Plan goals and track progress', 'module_access:planner', 'Goals are per-page. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (11, 'Vault', '/vault', 'General', 'Left sidebar → General', 'Shared team file/media storage', 'Access and manage shared files', 'module_access:vault', 'Supports private folders (admin). Pinnable.', 'client/src/components/AppLayout.jsx'),
  (12, 'Logs', '/logs', 'General', 'Left sidebar → General', 'Posting/automation job history', 'Review why posting succeeded/failed', 'module_access:logs', 'Read-only table. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (13, 'Activity', '/activity', 'General', 'Left sidebar → General', 'Workspace audit timeline', 'See the activity/audit trail', 'module_access:activity', 'Read-only table. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (14, 'Accounts', '/accounts', 'General', 'Left sidebar → General', 'Admin account/invite management', 'Manage accounts and invites', 'admin only', 'Locked (padlock) for non-admins. Pinnable.', 'client/src/components/AppLayout.jsx'),
  (15, 'Settings', '/settings', 'General', 'Left sidebar → General', 'Posting rules, pages, templates, automation', 'Open settings', 'module_access:settings', 'Sub-nav: Posting / Pages (admin) / Templates (flag) / Automation (admin). Pinnable.', 'client/src/components/AppLayout.jsx'),
  (16, 'Insights → Overview', '/insights?view=overview', 'Workspace (Insights sub-nav)', 'Left sidebar → Insights sub-nav', 'Default insights digest', 'Reach/audience/messaging snapshot', 'module_access:insights', 'Shown when on /insights.', 'client/src/components/AppLayout.jsx'),
  (17, 'Insights → Performance', '/insights?view=performance', 'Workspace (Insights sub-nav)', 'Left sidebar → Insights sub-nav', 'Per-metric performance vs previous period', 'Metric cards with export', 'module_access:insights', NULL, 'client/src/components/AppLayout.jsx'),
  (18, 'Insights → Messaging', '/insights?view=messaging', 'Workspace (Insights sub-nav)', 'Left sidebar → Insights sub-nav', 'Who is messaging the page', 'Per-channel contact trends', 'module_access:insights', NULL, 'client/src/components/AppLayout.jsx'),
  (19, 'Insights → Contents', '/insights?view=contents', 'Workspace (Insights sub-nav)', 'Left sidebar → Insights sub-nav', 'Per-post performance table', 'Sort/filter post performance', 'module_access:insights', NULL, 'client/src/components/AppLayout.jsx'),
  (20, 'Contents → Posts & reels', '/post-pool?view=contents', 'Workspace (Contents sub-nav)', 'Left sidebar → Contents sub-nav', 'Posts & reels pool', 'Default post-pool view', 'module_access:post-pool', NULL, 'client/src/components/AppLayout.jsx'),
  (21, 'Contents → Stories', '/post-pool?view=stories', 'Workspace (Contents sub-nav)', 'Left sidebar → Contents sub-nav', '24-hour stories', 'Post/manage FB/IG stories', 'module_access:post-pool', 'IG option needs a linked Instagram account.', 'client/src/components/AppLayout.jsx'),
  (22, 'Contents → Comments', '/post-pool?view=comments', 'Workspace (Contents sub-nav)', 'Left sidebar → Contents sub-nav', 'Comments inbox', 'Reply to and triage comments', 'module_access:post-pool', 'Renders as a full-height inbox.', 'client/src/components/AppLayout.jsx'),
  (23, 'Settings → Posting', '/settings?section=posting', 'General (Settings sub-nav)', 'Left sidebar → Settings sub-nav', 'Posting rules', 'Scheduled publishing, timezone, low-pool alerts', 'module_access:settings', NULL, 'client/src/components/AppLayout.jsx'),
  (24, 'Settings → Pages', '/settings?section=pages#facebook-pages', 'General (Settings sub-nav)', 'Left sidebar → Settings sub-nav', 'Connected Facebook pages', 'Connect/reconnect/manage pages', 'admin only', NULL, 'client/src/components/AppLayout.jsx'),
  (25, 'Settings → Templates', '/settings?section=templates', 'General (Settings sub-nav)', 'Left sidebar → Settings sub-nav', 'Creatomate templates', 'Manage reusable video templates', 'module_access:settings + env.templatesEnabled', 'Hidden when the templates feature flag is off.', 'client/src/components/AppLayout.jsx'),
  (26, 'Settings → Automation', '/settings?section=automation', 'General (Settings sub-nav)', 'Left sidebar → Settings sub-nav', 'Automation rules', 'Configure automation', 'admin only', NULL, 'client/src/components/AppLayout.jsx'),
  (27, 'Shop → Products', '/shop/products', 'Shop sub-nav', 'Shop page → left sub-rail', 'Product catalog', 'Browse/manage products, build a cart', 'module_access:products', 'Default (index redirects here). Add/edit/delete = admin.', 'client/src/pages/Shop/ShopLayout.jsx'),
  (28, 'Shop → Orders', '/shop/orders', 'Shop sub-nav', 'Shop page → left sub-rail', 'Confirmed orders', 'Track and update order status', 'module_access:products', 'Staff filter/"processed by" = admin.', 'client/src/pages/Shop/ShopLayout.jsx'),
  (29, 'Shop → Receipts', '/shop/receipts', 'Shop sub-nav', 'Shop page → left sub-rail', 'Stored receipts', 'Upload/open/delete receipts', 'module_access:products', 'Non-admins see their own; staff filter = admin.', 'client/src/pages/Shop/ShopLayout.jsx'),
  (30, 'Shop → Discounts', '/shop/discounts', 'Shop sub-nav', 'Shop page → left sub-rail', 'Cart/coupon discount rules', 'Manage discounts', 'module_access:products', 'Writes = admin; non-admins read-only.', 'client/src/pages/Shop/ShopLayout.jsx'),
  (31, 'Quick Access', 'pinned group', 'Quick Access', 'Left sidebar → top group', 'Pinned nav shortcuts', 'Fast access to pinned items', 'all users', 'Shown only when ≥1 item is pinned. Rovi can pin/unpin items (pin action).', 'client/src/components/AppLayout.jsx'),
  (32, 'Pin to Quick Access', 'pin control', 'per nav row', 'Trailing edge of each nav row', 'Pin/unpin a nav item', 'Add/remove from Quick Access', 'all users', 'Revealed on row hover. Persisted in localStorage pwise:pinned-nav. Rovi can operate it (pin action).', 'client/src/components/AppLayout.jsx'),
  (33, 'Collapse sidebar', 'collapse control', 'Sidebar top', 'Left sidebar top', 'Collapse to an icons-only rail', 'Toggle icon-only vs full sidebar', 'all users', 'Persisted in localStorage pwise:sidebar-collapsed. Rovi can operate it (sidebar action).', 'client/src/components/AppLayout.jsx'),
  (34, 'Switch Page', 'page-picker card', 'Page card', 'Bottom-left footer', 'Active Facebook page + follower count', 'Open the page switcher', 'all users when ≥1 page connected', 'Opens a modal listing connected pages; disabled while switching. Rovi can switch pages (page action).', 'client/src/components/AppLayout.jsx'),
  (35, '+ Connect a page', '/settings', 'Page card (empty state)', 'Bottom-left footer', 'No pages connected prompt', 'Go to Settings to connect a page', 'admin only', 'Shown only when no pages are connected.', 'client/src/components/AppLayout.jsx'),
  (36, 'Account menu', 'user menu', 'Account menu', 'Bottom-left account button', 'The signed-in user', 'Open the account dropdown', 'all users', 'Opens profile/privacy/theme/logout.', 'client/src/components/AppLayout.jsx'),
  (37, 'User Profile', '/profile', 'Account menu', 'Bottom-left account menu', 'Profile page', 'View/edit your profile', 'all users', 'Not module-gated.', 'client/src/components/AppLayout.jsx'),
  (38, 'Privacy Policy', '/privacy', 'Account menu', 'Bottom-left account menu', 'Privacy policy', 'Read the privacy policy', 'public route', 'Reachable even when logged out. Rovi can navigate here unconditionally.', 'client/src/components/AppLayout.jsx'),
  (39, 'Theme toggle (Light/Dark)', 'theme toggle', 'Account menu', 'Bottom-left account menu', 'Color theme switch', 'Toggle dark/light theme', 'all users', 'Label/icon swap with the current theme. Rovi can switch it directly (theme action) — no need to open the menu.', 'client/src/components/AppLayout.jsx'),
  (40, 'Logout', 'logout action', 'Account menu', 'Bottom-left account menu (danger)', 'Sign out', 'End the session', 'all users', 'Rovi does NOT perform logout.', 'client/src/components/AppLayout.jsx');
INSERT INTO public.screens (sort_order, screen, route_or_surface, layout_pattern, purpose, primary_regions, primary_actions, visible_to, depends_on, source_reference) VALUES
  (1, 'Login', '/login', 'Centered auth card + OTP modal', 'Sign in (invite-only) with new-device email OTP', 'Email+password form, locked-account banner, footer links, OTP modal', 'Log in; enter/verify OTP; trust device; resend code', 'public', 'Backend up; an existing invited account', 'client/src/pages/Login/LoginPage.jsx'),
  (2, 'Signup', '/signup?token=', 'Centered auth card', 'Create an account from a single-use invite link', 'Invite-validation state, name/email/password/confirm form', 'Validate invite; create account', 'public', 'A valid, unused invite token', 'client/src/pages/Signup/SignupPage.jsx'),
  (3, 'Privacy Policy', '/privacy', 'Long-form legal document', 'Static privacy/data-deletion policy', 'Header, numbered policy sections, back-to-login footer', 'Read; email contact links; back to login', 'public', 'none', 'client/src/pages/Privacy/PrivacyPolicyPage.jsx'),
  (4, 'Checkout', '/checkout?ref=', 'Standalone 3-step page + discount drawer', 'Self-contained cart checkout opened in a new tab from Shop', 'Item list, discount panel, summary, delivery form, agreement panel', 'Apply discounts/codes; place order; fill delivery; generate agreement', 'public', 'A localStorage checkout snapshot under ref', 'client/src/pages/Checkout/CheckoutPage.jsx'),
  (5, 'Order Agreement (customer)', '/agreement/:token', 'Centered document card with countdown', 'Public customer view to read + confirm an order agreement', 'Countdown bar, language dropdown, agreement document, agree checkbox + Confirm', 'Switch language; agree; confirm order (creates the order)', 'public (token is the capability)', 'A valid, unexpired agreement token', 'client/src/pages/Agreement/AgreementViewer.jsx'),
  (6, 'Satisfaction Survey (customer)', '/survey/:token', 'Centered card, two questions', 'Public post-conversation CSAT + NPS survey (one-shot)', 'CSAT faces (1–5), NPS 0–10 scale, optional comment, submit', 'Pick satisfaction and NPS; write a comment; send', 'public (token is the capability)', 'A valid, unsubmitted survey token', 'client/src/pages/Survey/SurveyPage.jsx'),
  (7, 'Post Insights', '/post/:id/insights', 'Standalone tab: header + granularity + chart + range sidebar', 'Standalone per-post metrics, opened in a new tab from the post viewer', 'Header, Day/Week/Month control, engagement bar chart, range sidebar, Download PDF', 'Change granularity; pick a date range; download a branded PDF', 'authed (shell-less)', 'Post exists; page audience data', 'client/src/pages/PostInsights/PostInsightsPage.jsx'),
  (8, 'Dashboard', '/dashboard', 'Page head + stat grid + two info cards', 'Overview of automated posting for the active page', 'Stat cards, automation card, pipeline card, low-pool banner', 'Go to Upload / Settings / Contents / Logs', 'authed (core)', 'A connected/healthy active page (page-scoped)', 'client/src/pages/Dashboard/DashboardPage.jsx'),
  (9, 'Content Calendar', '/content-calendar', 'Page head + full-height month calendar', 'Cross-page month calendar of scheduled posts + notes', 'Month grid, per-day cells, create-post & notes dialogs', 'Browse month; open/create posts & notes on days', 'module_access:content-calendar', 'Page-independent', 'client/src/pages/ContentCalendar/ContentCalendarPage.jsx'),
  (10, 'Planner', '/planner', 'Page head + filter/progress panel + goal list', 'Set measurable per-page goals and track progress', 'Filter popover, progress hero, goal cards, goal form modal', 'Create/edit/delete goals; filter by status/cadence', 'module_access:planner', 'At least one connected page', 'client/src/pages/Planner/PlannerPage.jsx'),
  (11, 'Analytics', '/analytics', 'Page head + range toolbar + stat grid + charts + table', 'Page-level performance over time', 'Range control, KPI cards, line charts, top-posts table', 'Change range; download PDF; open a top post', 'module_access:analytics', 'Healthy active page (page-scoped)', 'client/src/pages/Analytics/AnalyticsPage.jsx'),
  (12, 'Insights — Overview', '/insights?view=overview', 'Page head + metric tiles + chart + top-content table', 'Snapshot digest of reach/audience/messaging', 'Followers headline, selectable metric tiles, chart, top content', 'Select a metric tile; change range; all-pages PDF', 'module_access:insights', 'Active page selected', 'client/src/pages/Insights/InsightsPage.jsx'),
  (13, 'Insights — Performance', '/insights?view=performance', 'Page head + metric-card grid', 'Per-metric performance vs previous period', 'Metric cards (value, delta, sparkline, per-card export)', 'Change range; export per-card/full/all-pages PDFs', 'module_access:insights', 'Active page + insights data', 'client/src/pages/Insights/InsightsPage.jsx'),
  (14, 'Insights — Messaging', '/insights?view=messaging', 'Page head + tiles + chart + per-channel bars', 'Who is messaging the page and the trend', 'Selectable tiles + chart, per-channel new/returning bars', 'Select a tile; change range; all-pages PDF', 'module_access:insights', 'Active page', 'client/src/pages/Insights/InsightsPage.jsx'),
  (15, 'Insights — Contents', '/insights?view=contents', 'Page head + sortable/filterable table', 'Per-post performance table for the period', 'Media-type filter, sortable columns with thumbnails', 'Filter by media; sort columns', 'module_access:insights', 'Active page', 'client/src/pages/Insights/InsightsPage.jsx'),
  (16, 'Contents — Posts & reels', '/post-pool', 'Page head + toolbar + card grid + viewer + modals', 'Manage the pool of posts the agent can publish', 'Status/date filters, post cards, viewer, edit/delete/export modals', 'Filter; open viewer; edit caption/schedule; delete; retry; export; upload', 'module_access:post-pool', 'Healthy active page (page-scoped)', 'client/src/pages/PostPool/ContentsView.jsx'),
  (17, 'Contents — Stories', '/post-pool?view=stories', 'Page head + card grid + composer modal', '24-hour FB/IG stories', 'Story cards (platform, status, expiry), story composer', 'Post story; retry failed; delete; paginate', 'module_access:post-pool', 'Active page; IG option needs a linked Instagram account', 'client/src/pages/PostPool/ContentsView.jsx'),
  (18, 'Contents — Comments', '/post-pool?view=comments', 'Full-height inbox: list panel + reply panel', 'Reply to and triage comments across posts', 'Filter tabs, comment list, FB-style detail/reply pane', 'Filter; select; reply as page; mark done; message the commenter', 'module_access:post-pool', 'Active page; live via SSE', 'client/src/pages/PostPool/ContentsView.jsx'),
  (19, 'Upload Post', '/upload', 'Page head + composer (form + live preview) + modals', 'Create/schedule a post, optional template render', 'Use-template toggle, media/caption fields, schedule toggle, preview', 'Pick media; use a template + generate video; write caption; schedule or post now', 'module_access:upload', 'Healthy active page; template features need env.templatesEnabled', 'client/src/components/UploadPostForm.jsx'),
  (20, 'Shop (layout)', '/shop', 'Left sub-nav rail + outlet', 'Shell for the Shop module sections', 'Shop sub-nav + section content', 'Navigate between shop sections', 'module_access:products', 'Healthy active page (page-scoped)', 'client/src/pages/Shop/ShopLayout.jsx'),
  (21, 'Shop — Products', '/shop/products', 'Head + product grid + quick-view + cart drawer + form', 'Browse/manage catalog and build a cart', 'Product tiles, quick-view modal, cart drawer, product form (admin)', 'View product; choose variant/qty; add to cart; checkout; admin: add/edit/delete', 'module_access:products (writes = admin)', 'Active page; a page currency', 'client/src/pages/Products/ProductsPage.jsx'),
  (22, 'Shop — Discounts', '/shop/discounts', 'Head + discount card grid + editor modal', 'Manage cart/coupon discount rules', 'Discount cards, editor modal', 'Admin: add/edit/delete; non-admins read-only', 'module_access:products (writes = admin)', 'Active page selected', 'client/src/pages/Shop/DiscountsPage.jsx'),
  (23, 'Shop — Orders', '/shop/orders', 'Page head + filters + paginated table + detail modal', 'Track confirmed orders for the page', 'Status/staff filters, orders table, order-detail modal', 'Filter; change order status; view detail', 'module_access:products (staff filter = admin)', 'Active page selected', 'client/src/pages/Shop/OrdersPage.jsx'),
  (24, 'Shop — Receipts', '/shop/receipts', 'Page head + filters/upload + receipt grid + delete modal', 'Store photo/PDF receipts', 'Receipt cards, upload, delete confirm', 'Upload; open; delete; admin: filter by staff', 'module_access:products (staff filter = admin)', 'Active page selected', 'client/src/pages/Shop/ReceiptsPage.jsx'),
  (25, 'Settings', '/settings', 'Page head + single content card that swaps sections', 'Configure posting, pages, templates, automation', 'Posting form; Pages (admin); Templates (flag); Automation (admin)', 'Toggle publishing; edit timezone/threshold/owner; manage pages/templates/automation', 'module_access:settings (Pages/Automation = admin; Templates = flag)', 'Pages section depends on Facebook OAuth', 'client/src/pages/Settings/SettingsPage.jsx'),
  (26, 'Logs', '/logs', 'Page head + paginated table', 'History of every posting attempt', 'Posting-logs table, pagination', 'Page through logs', 'module_access:logs', 'Page-independent', 'client/src/pages/Logs/LogsPage.jsx'),
  (27, 'Activity', '/activity', 'Page head + paginated table', 'Audit timeline of post/note actions', 'Activity table, pagination', 'Page through activity', 'module_access:activity', 'Page-independent', 'client/src/pages/Activity/ActivityPage.jsx'),
  (28, 'Accounts', '/accounts', 'Page head + invite card + tables + modals', 'Admin user & invite management', 'Invite-link card, accounts table, invites table, access modals', 'Generate/copy/delete invites; toggle admin; edit access; activate/deactivate; unlock; delete', 'admin only', 'Admin session; super-admin for transfer', 'client/src/pages/Accounts/AccountsPage.jsx'),
  (29, 'Messaging', '/messages', 'Left mode rail + list panel + thread panel + drawers', 'Unified customer inbox + agent-to-agent DMs + templates/NPS', 'Mode rail, conversation list (page filter, AI/For-you), thread + composer, drawers', 'Filter; select/reply; take over/transfer/hand back; attach media; enhance; DM teammates; NPS metrics', 'module_access:messages', 'Healthy active page (page-scoped); live SSE; connections for A2A', 'client/src/pages/Messaging/MessagingPage.jsx'),
  (30, 'Connections', '/connections', 'Centered head + search/list card', 'Manage teammate connections for A2A messaging', 'Search box, search results, requests, your connections, sent requests', 'Search; connect/accept/decline/cancel/remove; Message (to /messages?dm=)', 'module_access:connections', 'Live via SSE', 'client/src/pages/Connections/ConnectionsPage.jsx'),
  (31, 'Vault', '/vault', 'Page head + browser (breadcrumb + toolbar) + grid + modals', 'Shared team file/media storage with AI visibility + private folders', 'Breadcrumbs, search/type/sort toolbar, folder/file cards, upload/new-folder/preview modals', 'Upload/drag-drop; create folders; move; download; delete; toggle AI visibility; admin: private folders', 'module_access:vault (private-folder access = admin)', 'Page-independent (team-shared)', 'client/src/pages/Vault/VaultPage.jsx'),
  (32, 'User Profile', '/profile', 'Page head + profile card grid + email/avatar modals', 'View/update account, photo, email, security', 'Hero card (avatar), account-details form, status card, security card', 'Edit name; change avatar; change email via code; go to change-password', 'authed (not module-gated)', 'none', 'client/src/pages/Profile/ProfilePage.jsx'),
  (33, 'Change Password', '/profile/change-password', 'Back-link + stepper + card + OTP modal', '3-step password change (verify → emailed code → new password)', 'Step indicator, stage card, verification-code modal', 'Confirm current password; enter emailed code; set new password', 'authed (not module-gated)', 'Emailed OTP delivery', 'client/src/pages/Profile/ChangePasswordPage.jsx');
INSERT INTO public.controls (sort_order, screen, section, control_name, control_type, viewport_position, meaning, purpose, when_visible, assistant_guidance, source_reference) VALUES
  (1, 'All (app shell)', 'Sidebar top', 'Collapse sidebar / Expand sidebar', 'toggle button', 'Left sidebar top', 'Sidebar width state', 'Collapse the sidebar to an icons-only rail', 'always (desktop)', 'Rovi can do this directly with the sidebar action (collapse/expand/toggle) — no need to click.', 'client/src/components/AppLayout.jsx'),
  (2, 'All (app shell)', 'Sidebar nav row', 'Pin {item} to Quick Access', 'toggle button (pushpin)', 'Trailing edge of a nav row', 'Whether a page is pinned', 'Pin/unpin a nav item to Quick Access', 'on nav-row hover', 'Rovi can do this directly with the pin action (target = the nav label).', 'client/src/components/AppLayout.jsx'),
  (3, 'All (app shell)', 'Sidebar footer', 'Switch Page', 'modal-trigger', 'Bottom-left, above account', 'The active Facebook page', 'Open the page switcher to change the active page', 'when ≥1 page connected', 'Rovi can switch the active page directly with the page action (target = page name).', 'client/src/components/AppLayout.jsx'),
  (4, 'All (app shell)', 'Account menu', 'Light theme / Dark theme', 'theme toggle', 'Bottom-left account menu', 'Current color theme', 'Toggle dark/light theme (label shows the theme you switch TO)', 'when account menu open', 'Rovi can switch the theme directly with the theme action (dark/light/toggle) — it does NOT need to open the menu.', 'client/src/components/AppLayout.jsx'),
  (5, 'All (app shell)', 'Account menu', 'User Profile', 'menu link', 'Bottom-left account menu', 'Profile page', 'Open the profile page', 'when menu open', 'Tell the user to open the account menu, then User Profile — or Rovi can navigate to /profile.', 'client/src/components/AppLayout.jsx'),
  (6, 'All (app shell)', 'Account menu', 'Logout', 'button (danger)', 'Bottom-left account menu', 'Sign out', 'End the session', 'when menu open', 'Rovi does NOT log the user out; tell them to click Logout themselves.', 'client/src/components/AppLayout.jsx'),
  (7, 'All (app shell)', 'Page-switcher modal', 'Refresh page data from Facebook', 'icon button', 'Modal header', 'Re-sync page names/followers', 'Pull fresh page data; flag expired tokens', 'when the picker is open', 'Tell the user to click the refresh icon in the Switch-page dialog.', 'client/src/components/AppLayout.jsx'),
  (8, 'All (app shell)', 'Reconnect banner/gate', 'Reconnect / Re-check', 'button', 'Top banner or full-screen gate', 'Broken Facebook connection', 'Send an admin to reconnect; re-check token health', 'when the active page token is broken', 'Tell admins to click Reconnect; others should ask an admin.', 'client/src/components/AppLayout.jsx'),
  (9, 'All (app shell)', 'Wise Assistant', 'Ask me a question', 'text input + Ask button', 'Assistant chat popover/side panel', 'Question to Rovi', 'Send a message to the Wise Assistant', 'when the chat is open', 'This is Rovi itself.', 'client/src/components/DevScreenAgent.jsx'),
  (10, 'All (app shell)', 'Wise Notes', 'Show notes / Hide notes', 'menu toggle', 'Popup beside the notes launcher', 'Sticky-note visibility', 'Show or hide all sticky notes', 'when the notes menu is open', 'Rovi can do this directly with the notes action (show/hide/toggle).', 'client/src/components/WiseNotes.jsx'),
  (11, 'All (app shell)', 'Wise Notes', 'Create a note', 'menu button', 'Popup beside the notes launcher', 'New sticky note', 'Open the sticky-note editor (max 6)', 'when the menu is open and <6 notes', 'Tell the user to press the notes launcher and click Create a note.', 'client/src/components/WiseNotes.jsx'),
  (12, 'Dashboard', 'Page head', '+ Upload post', 'primary button', 'Top-right toolbar', 'Shortcut to Upload', 'Go to the Upload screen', 'always', 'Tell the user to click "+ Upload post" (top-right), or Rovi can navigate to /upload.', 'client/src/pages/Dashboard/DashboardPage.jsx'),
  (13, 'Dashboard', 'Automation card', 'Edit settings', 'button', 'Left card', 'Shortcut to Settings', 'Open Settings', 'always', 'Tell the user to click "Edit settings".', 'client/src/pages/Dashboard/DashboardPage.jsx'),
  (14, 'Dashboard', 'Pipeline card', 'Manage pool / View logs', 'buttons', 'Right card', 'Shortcuts to Contents / Logs', 'Open the Contents pool or Logs', 'always', 'Tell the user to click "Manage pool" or "View logs".', 'client/src/pages/Dashboard/DashboardPage.jsx'),
  (15, 'Analytics', 'Page head', '7 days / 28 days / 90 days', 'segmented control', 'Top-right toolbar', 'Time range', 'Switch the analytics window', 'always', 'Tell the user (or Rovi can fill via ui) to pick a range.', 'client/src/pages/Analytics/AnalyticsPage.jsx'),
  (16, 'Analytics', 'Page head', 'Download report', 'button', 'Top-right toolbar', 'PDF export', 'Build a PDF of the current range', 'disabled until data loads', 'Tell the user to click "Download report".', 'client/src/pages/Analytics/AnalyticsPage.jsx'),
  (17, 'Insights', 'Sub-nav', 'Overview / Performance / Messaging / Contents', 'sidebar sub-tabs (?view=)', 'Left sidebar under Insights', 'Which insights section', 'Switch the Insights sub-view', 'when on Insights', 'Rovi can navigate to /insights?view=... to switch sub-tab.', 'client/src/components/AppLayout.jsx'),
  (18, 'Insights', 'Page head', 'All pages PDF', 'button', 'Top-right', 'Combined all-pages metrics PDF', 'Download an all-pages report', 'always', 'Tell the user to click "All pages PDF".', 'client/src/pages/Insights/InsightsPage.jsx'),
  (19, 'Contents — Posts & reels', 'Toolbar', 'Filter by status', 'dropdown', 'Top toolbar', 'Status filter', 'Filter posts by ready/posted/failed/etc.', 'always', 'Tell the user to use the status dropdown (Rovi can fill it via ui).', 'client/src/pages/PostPool/ContentsView.jsx'),
  (20, 'Contents — Posts & reels', 'Toolbar', 'Filter by date range', 'popover (calendar icon)', 'Top toolbar', 'Posted-date window', 'Filter posts by date', 'always', 'Tell the user to click the calendar icon.', 'client/src/pages/PostPool/ContentsView.jsx'),
  (21, 'Contents — Posts & reels', 'Toolbar', '+ Upload post', 'primary button', 'Top-right', 'Shortcut to Upload', 'Go to Upload', 'always', 'Rovi can navigate to /upload.', 'client/src/pages/PostPool/ContentsView.jsx'),
  (22, 'Contents — Posts & reels', 'Post card', 'Post options (⋮) → Edit / Delete', 'kebab menu', 'Card top-right', 'Per-post actions', 'Edit caption/schedule or delete', 'always', 'Tell the user to click the ⋮ on a post.', 'client/src/pages/PostPool/ContentsView.jsx'),
  (23, 'Upload Post', 'Options', 'Use template', 'toggle', 'Top of the form', 'Template vs direct upload', 'Switch to the Creatomate template flow', 'when the templates feature is enabled', 'Tell the user to flip "Use template" (Rovi can toggle via ui).', 'client/src/components/UploadPostForm.jsx'),
  (24, 'Upload Post', 'Schedule', 'Scheduled posting', 'toggle', 'Schedule section', 'Scheduled vs immediate', 'Choose a scheduled slot or the next run', 'always', 'Tell the user to toggle "Scheduled posting".', 'client/src/components/UploadPostForm.jsx'),
  (25, 'Upload Post', 'Footer', 'Add to pool / Post now', 'submit button', 'Bottom / modal footer', 'Save or publish', 'Save the post (scheduled) or post now', 'always', 'Tell the user to click "Add to pool" (or "Post now").', 'client/src/components/UploadPostForm.jsx'),
  (26, 'Shop', 'Sub-nav', 'Products / Orders / Receipts / Discounts', 'tab links', 'Left sub-nav rail', 'Shop section', 'Switch the Shop sub-screen', 'always in Shop', 'Rovi can navigate to /shop/products, /shop/orders, etc.', 'client/src/pages/Shop/ShopLayout.jsx'),
  (27, 'Shop — Products', 'Head', 'Cart', 'drawer trigger', 'Top-right', 'Shopping cart', 'Open the cart drawer (badge = count)', 'always', 'Tell the user to click "Cart".', 'client/src/pages/Products/ProductsPage.jsx'),
  (28, 'Shop — Products', 'Head', 'Add product', 'button', 'Top-right', 'Create a product', 'Open the product form', 'admin only, page selected', 'Tell the admin to click "Add product".', 'client/src/pages/Products/ProductsPage.jsx'),
  (29, 'Shop — Products', 'Cart drawer', 'Proceed to checkout', 'button', 'Right-side drawer', 'Open checkout', 'Open the checkout tab for ticked items', 'when cart open', 'Tell the user to tick items and click "Proceed to checkout".', 'client/src/pages/Products/ProductsPage.jsx'),
  (30, 'Content Calendar', 'Month header', 'Today / Previous / Next month', 'buttons', 'Calendar top bar', 'Month navigation', 'Move the calendar view', 'always', 'Tell the user to use Today and the ‹ › arrows.', 'client/src/components/CalendarMonth.jsx'),
  (31, 'Content Calendar', 'Day cell', 'Plan content for this day', 'day cell (button)', 'Calendar grid', 'A calendar day', 'Open the day modal to add a post/note', 'always', 'Tell the user to click a day to plan content/notes.', 'client/src/components/CalendarMonth.jsx'),
  (32, 'Planner', 'Page head', '+ New goal', 'primary button', 'Top-right', 'Create a goal', 'Open the goal form', 'disabled if no pages connected', 'Tell the user to click "+ New goal".', 'client/src/pages/Planner/PlannerPage.jsx'),
  (33, 'Planner', 'Panel toolbar', 'Toggle filters', 'popover (funnel)', 'Top-right of the panel', 'Status + cadence filters', 'Filter goals', 'always', 'Tell the user to click the filter (funnel) icon.', 'client/src/pages/Planner/PlannerPage.jsx'),
  (34, 'Vault', 'Browser top', 'Create a new folder', 'button', 'Top-right of the browser', 'New folder', 'Open the new-folder modal (admins can make it private)', 'always', 'Tell the user to click "Create a new folder".', 'client/src/pages/Vault/VaultPage.jsx'),
  (35, 'Vault', 'Browser top', 'Upload files', 'button', 'Top-right', 'Upload', 'Open the file picker (also drag-drop)', 'always', 'Tell the user to click "Upload files" or drag files onto the Vault. Rovi cannot open the OS file picker.', 'client/src/pages/Vault/VaultPage.jsx'),
  (36, 'Vault', 'Toolbar', 'Search / Type filter / Sort', 'search + dropdowns', 'Toolbar', 'Browse controls', 'Filter and sort the current folder', 'always', 'Tell the user to use the search box and the Type/Sort dropdowns.', 'client/src/pages/Vault/VaultPage.jsx'),
  (37, 'Vault', 'File card', 'Actions (⋮) → Details / Visible-to-AI / Download / Delete', 'kebab menu', 'On each card', 'Per-file actions', 'Manage a file and its AI visibility', 'on card', 'Tell the user to click the ⋮ on a file.', 'client/src/pages/Vault/VaultPage.jsx'),
  (38, 'Accounts', 'Page head', '+ Generate login link', 'primary button', 'Top-right', 'Create an invite', 'Open the module-access modal to mint a single-use invite', 'admin only', 'Tell the admin to click "+ Generate login link".', 'client/src/pages/Accounts/AccountsPage.jsx'),
  (39, 'Accounts', 'Row menu', 'Options for {name} (gear)', 'kebab/gear menu', 'Row trailing edge', 'Per-user admin actions', 'Role, module access, lock, active state', 'admin only, not on own row', 'Tell the admin to click the gear on a user row.', 'client/src/pages/Accounts/AccountsPage.jsx'),
  (40, 'Settings', 'Sub-nav', 'Posting / Pages / Templates / Automation', 'sidebar sub-tabs (?section=)', 'Left sidebar under Settings', 'Which settings section', 'Switch the settings panel', 'when on Settings', 'Rovi can navigate to /settings?section=posting (Pages/Automation are admin).', 'client/src/components/AppLayout.jsx'),
  (41, 'Settings', 'Posting', 'Scheduled publishing', 'toggle', 'Posting form', 'Master posting switch', 'Enable/disable due scheduled posts', 'Posting section', 'Tell the user to flip "Scheduled publishing" (Rovi can toggle via ui).', 'client/src/pages/Settings/SettingsPage.jsx'),
  (42, 'Settings', 'Posting', 'Save settings', 'submit button', 'Bottom of the form', 'Persist posting settings', 'Save changes', 'Posting section', 'Tell the user to click "Save settings".', 'client/src/pages/Settings/SettingsPage.jsx'),
  (43, 'Connections', 'Card', 'Search teammates', 'search input', 'Top of the card', 'Teammate lookup', 'Live-search people to connect with', 'always', 'Tell the user to type a name/email (Rovi can fill via ui).', 'client/src/pages/Connections/ConnectionsPage.jsx'),
  (44, 'Connections', 'Your connections', 'Message', 'button', 'Each connection row', 'Open a DM', 'Jump to /messages?dm= for that person', 'when connections exist', 'Tell the user to click "Message" to DM a connection.', 'client/src/pages/Connections/ConnectionsPage.jsx'),
  (45, 'Messaging', 'Mode rail', 'Agent to Customer / Agent to Agent / Templates / NPS', 'mode cards', 'Far-left vertical rail', 'Inbox mode', 'Switch between customer inbox, teammate DMs, templates, NPS', 'always', 'Tell the user to click the icons in the left rail.', 'client/src/pages/Messaging/MessagingPage.jsx'),
  (46, 'Messaging', 'Inbox header', 'AI Agent / For you', 'segmented tabs', 'List panel', 'Which queue', 'AI-handled threads vs. the live-agent queue', 'customer mode', 'Tell the user to switch between "AI Agent" and "For you".', 'client/src/pages/Messaging/MessagingPage.jsx'),
  (47, 'Messaging', 'Locked composer', 'Take over conversation', 'button', 'Composer area', 'Claim an AI thread', 'Let the human reply on an AI-handled thread', 'on an AI-handled thread', 'Tell the user to click "Take over conversation".', 'client/src/pages/Messaging/MessagingPage.jsx'),
  (48, 'Messaging', 'Composer', 'Enhance with AI', 'button', 'Inside the input', 'Polish the draft', 'Improve the draft with AI', 'when a draft exists', 'Tell the user to click "Enhance with AI".', 'client/src/pages/Messaging/MessagingPage.jsx');
INSERT INTO public.assistant_playbook (sort_order, user_intent, best_destination, where_it_lives, guidance_to_give, caveats) VALUES
  (1, 'Switch to dark or light theme', 'Theme action', 'Bottom-left account menu (theme toggle)', 'Emit a theme action, e.g. {"type":"theme","value":"dark"} (or "light"/"toggle"). No need to open the account menu.', 'Purely a UI preference; never changes account data.'),
  (2, 'Show or hide my sticky notes', 'Notes action', 'Wise Notes launcher near the robot', 'Emit a notes action, e.g. {"type":"notes","op":"hide"} (or "show"/"toggle").', 'Notes are a per-user UI aid kept only in the browser.'),
  (3, 'Collapse or expand the sidebar', 'Sidebar action', 'Left sidebar top (collapse control)', 'Emit a sidebar action, e.g. {"type":"sidebar","op":"collapse"} (or "expand"/"toggle").', 'Cosmetic; persisted per browser.'),
  (4, 'Pin or unpin a page to Quick Access', 'Pin action', 'Trailing edge of each sidebar nav row', 'Emit a pin action with the sidebar label, e.g. {"type":"pin","target":"Analytics","op":"pin"} (or "unpin"/"toggle").', 'Only items the user can access can be pinned; the app re-checks access.'),
  (5, 'Switch to a different Facebook page', 'Page action', 'Bottom-left Switch Page card', 'Emit a page action with the page name, e.g. {"type":"page","target":"My Coffee Shop"}.', 'Changes the data context app-wide (Dashboard/Analytics/Pool/Messaging re-scope). Only do it when explicitly asked.'),
  (6, 'Reload / refresh the current page', 'Reload action', 'Current page', 'Emit {"type":"reload"}.', 'Loses any unsaved form input on the page.'),
  (7, 'Show me what the app stores in local storage', 'Read storage action', 'Browser local storage', 'Emit {"type":"read_storage"} (or with a specific key).', 'Credential-like values are masked; never reveal tokens.'),
  (8, 'Read the privacy policy', 'Privacy Policy', 'Bottom-left account menu → Privacy Policy (public route)', 'Navigate to /privacy. Reachable even when logged out.', 'None.'),
  (9, 'Open my profile / change my name or photo', 'User Profile', 'Bottom-left account menu → User Profile', 'Navigate to /profile. The user edits details there themselves.', 'Rovi must NOT change name, email, or photo — profile edits are the user’s to make.'),
  (10, 'Change my password', 'Change Password', '/profile/change-password (from the Profile page)', 'Navigate to /profile/change-password.', 'Requires the current password + an emailed code.'),
  (11, 'See analytics for the active page', 'Analytics', 'Left sidebar → Analytics', 'Navigate to /analytics; use the 7/28/90-day range control.', 'Needs a healthy connected page; requires analytics module access.'),
  (12, 'Open insight reports', 'Insights', 'Left sidebar → Insights (Overview/Performance/Messaging/Contents)', 'Navigate to /insights (add ?view= for a sub-tab).', 'Requires insights module access.'),
  (13, 'Manage or review posts', 'Contents (Post Pool)', 'Left sidebar → Contents', 'Navigate to /post-pool; sub-tabs Stories and Comments via ?view=.', 'Requires post-pool module access; page-scoped.'),
  (14, 'Create or schedule a post', 'Upload Post', 'Left sidebar → Upload', 'Navigate to /upload; toggle "Scheduled posting" for a slot.', 'Needs a healthy connected page; templates need the templates flag.'),
  (15, 'Reply to a customer', 'Messaging', 'Left sidebar → Messaging', 'Navigate to /messages; if the thread is AI-handled, "Take over conversation" first.', 'Requires messages module access; conversations are owned by one agent.'),
  (16, 'Manage the shop / products / orders', 'Shop', 'Left sidebar → Shop (Products/Orders/Receipts/Discounts)', 'Navigate to /shop/products (or the relevant sub-path).', 'Add/edit/delete require admin; requires products module access.'),
  (17, 'Find or reuse shared files', 'Vault', 'Left sidebar → Vault', 'Navigate to /vault; use search/type/sort to find files.', 'Private folders are admin-managed; Rovi cannot open the OS file explorer.'),
  (18, 'See why a post failed', 'Logs', 'Left sidebar → Logs', 'Navigate to /logs and review the status/message columns.', 'Requires logs module access.'),
  (19, 'Invite a teammate', 'Accounts', 'Left sidebar → Accounts', 'Navigate to /accounts and use "+ Generate login link".', 'Admin-only.'),
  (20, 'Connect or manage a Facebook page', 'Settings → Pages', 'Left sidebar → Settings → Pages', 'Navigate to /settings?section=pages#facebook-pages.', 'Admin-only section.'),
  (21, 'Look up my own data (orders, products, profile)', 'pwise API (read-only)', 'Server REST API, scoped to the user', 'Answer from the pwise_api tool (GET only, e.g. /api/auth/me, /api/orders). Do not navigate unless asked.', 'Read-only and user-scoped; Rovi can never modify account or data via the API.'),
  (22, 'Fill a field or toggle a control on this screen', 'UI action', 'The current screen', 'Emit a ui action, e.g. {"type":"ui","op":"fill","target":"Caption","value":"..."} or {"type":"ui","op":"toggle","target":"Scheduled posting"}.', 'Only visible controls on the current page; never password/OTP/file inputs, never profile/account screens.');
